INSERT INTO articles ("ID", "ARTICLE_CATEGORY_ID", "USER_ID", "TITLE", "SLUG", "EXCERPT", "BODY", "COVER_IMAGE_PATH", "IS_FEATURED", "IS_PUBLISHED", "PUBLICATION_STATUS", "REVIEWED_BY_USER_ID", "REVIEWED_AT", "PUBLISHED_AT", "CREATED_AT", "UPDATED_AT", "FEATURED_ORDER") VALUES (1, 1, NULL, 'When to See a Cardiologist', 'when-to-see-a-cardiologist', 'Learn the warning signs that mean you should book a cardiology appointment early.', '<p>Chest pain, breathlessness, and abnormal blood pressure are common reasons to seek a cardiology evaluation. Early diagnosis improves outcomes.</p><h2>The Importance of Early Detection</h2><p>Cardiovascular diseases are the leading cause of death globally, but many of these conditions are highly preventable and treatable when caught early. If you experience any of the following, it is crucial to consult a specialist:</p><ul><li>Persistent shortness of breath</li><li>Unexplained dizziness or lightheadedness</li><li>A fluttering sensation in your chest (palpitations)</li></ul><h2>Know Your Risk Factors</h2><p>Beyond symptoms, a family history of heart disease is a significant risk factor. Even if you feel perfectly healthy, scheduling a routine check-up after the age of 40 can help establish a baseline for your heart health.</p><blockquote>"Don''t wait for an emergency. Preventive cardiology focuses on lifestyle modifications, including diet and exercise counseling, alongside medication management to keep your heart functioning at its best."</blockquote><p>Your cardiologist may recommend an electrocardiogram (ECG), a stress test, or blood work to monitor your cholesterol and blood sugar levels.</p>', 'article-covers/cardiologist.png', 1, 1, 'draft', NULL, NULL, TO_TIMESTAMP('2026-05-27 04:43:18', 'YYYY-MM-DD HH24:MI:SS'), TO_TIMESTAMP('2026-05-26 17:18:21', 'YYYY-MM-DD HH24:MI:SS'), TO_TIMESTAMP('2026-05-27 04:50:50', 'YYYY-MM-DD HH24:MI:SS'), 0);
INSERT INTO articles ("ID", "ARTICLE_CATEGORY_ID", "USER_ID", "TITLE", "SLUG", "EXCERPT", "BODY", "COVER_IMAGE_PATH", "IS_FEATURED", "IS_PUBLISHED", "PUBLICATION_STATUS", "REVIEWED_BY_USER_ID", "REVIEWED_AT", "PUBLISHED_AT", "CREATED_AT", "UPDATED_AT", "FEATURED_ORDER") VALUES (2, 2, 10, 'Understanding Pediatric Care Milestones', 'understanding-pediatric-care', 'A guide for new parents on what to look out for in the first year of your baby''s life.', '<p>Your child''s development is critical during the first 12 months. Routine checks are not just for vaccines, but for monitoring motor skills, language development, and nutritional health.</p><h2>The First Six Months</h2><p>During the first few months, doctors will focus heavily on tracking your baby''s height, weight, and head circumference. They will also look for early social milestones, such as:</p><ul><li>Smiling in response to your voice</li><li>Following objects with their eyes</li><li>Lifting their head during tummy time</li></ul><p>By six months, most babies are rolling over, babbling, and reaching for toys. This is also a critical time to discuss introducing solid foods and establishing healthy sleep habits.</p><h2>Approaching the First Birthday</h2><p>As your baby approaches their first birthday, milestones like pulling up to stand, saying their first words, and playing simple games (like peek-a-boo) become important markers of cognitive and physical development.</p><blockquote>"Remember that every child develops at their own pace. The goal of pediatric visits is to provide support, answer your questions, and ensure your child is thriving."</blockquote>', 'articles/pediatrics.png', 1, 1, 'draft', NULL, NULL, TO_TIMESTAMP('2026-05-27 04:43:18', 'YYYY-MM-DD HH24:MI:SS'), TO_TIMESTAMP('2026-05-26 17:18:21', 'YYYY-MM-DD HH24:MI:SS'), TO_TIMESTAMP('2026-05-27 04:43:18', 'YYYY-MM-DD HH24:MI:SS'), 0);
INSERT INTO articles ("ID", "ARTICLE_CATEGORY_ID", "USER_ID", "TITLE", "SLUG", "EXCERPT", "BODY", "COVER_IMAGE_PATH", "IS_FEATURED", "IS_PUBLISHED", "PUBLICATION_STATUS", "REVIEWED_BY_USER_ID", "REVIEWED_AT", "PUBLISHED_AT", "CREATED_AT", "UPDATED_AT", "FEATURED_ORDER") VALUES (3, 3, NULL, 'Managing Mental Health in the Digital Age', 'managing-mental-health', 'Tips and tricks to stay grounded and manage stress in a hyper-connected world.', '<p>Digital detoxing is no longer just a trend, it is a medical necessity. Constant notifications cause our cortisol levels to spike. Taking 30 minutes of disconnected time daily can drastically improve your mental wellbeing.</p><h2>The Rise of Technostress</h2><p>The modern workplace often demands constant connectivity, leading to a phenomenon known as <strong>''technostress''</strong>. This can manifest as:</p><ul><li>Anxiety and irritability</li><li>Disrupted sleep patterns</li><li>A general feeling of overwhelm and burnout</li></ul><p>Setting boundaries is the first step. Try implementing a <em>''no-screens''</em> rule one hour before bedtime to allow your brain to naturally produce melatonin.</p><h2>Mindfulness in Practice</h2><p>Additionally, incorporating mindfulness practices into your daily routine can help combat digital fatigue. Simple breathing exercises, short walks without your phone, or engaging in a physical hobby can anchor you back to the present moment.</p><blockquote>"If feelings of anxiety or depression persist, do not hesitate to reach out to a mental health professional for personalized strategies."</blockquote>', 'article-covers/mental_health.png', 1, 1, 'draft', NULL, NULL, TO_TIMESTAMP('2026-05-27 04:43:18', 'YYYY-MM-DD HH24:MI:SS'), TO_TIMESTAMP('2026-05-26 17:18:21', 'YYYY-MM-DD HH24:MI:SS'), TO_TIMESTAMP('2026-05-27 04:50:50', 'YYYY-MM-DD HH24:MI:SS'), 0);
